		counter.increment?.apply(this, $$args);
	};

	var text = $.child(button);

	$.reset(button);
	$.template_effect(() => $.set_text(text, `${counter.count ?? ''}: ${counter.custom ?? ''}`));
	$.append($$anchor, button);
	$.pop();
